import java.util.*;class Player{static int W,H,x,y,lx,ly,cl,ch,wl,wh,dl,dh;static boolean fx,fc=true,ou;public static void main(String[]a){var s=new Scanner(System.in);W=s.nextInt();H=s.nextInt();cl=wl=dl=0;ch=wh=dh=W-1;int n=s.nextInt();x=s.nextInt();y=s.nextInt();for(;;){char b=s.next().charAt(0);int tx=x,ty=y;if(b=='W'){cl=wl;ch=wh;}else if(b=='C'){cl=dl;ch=dh;}else if(b=='S'){if(!fc){if(!found()){lx=tx;ly=ty;System.out.println(x+" "+y);continue;}}};if(cl>=ch){if(!found()){lx=tx;ly=ty;System.out.println(x+" "+y);continue;}}fc=false;if(fx)y=get(y,H-1);else x=get(x,W-1);lx=tx;ly=ty;System.out.println(x+" "+y);}}static boolean found(){int tx=x,ty=y;if(fx)y=(cl+ch)/2;else{x=(cl+ch)/2;fx=true;cl=wl=dl=0;ch=wh=dh=H-1;}fc=true;return!(x==tx&&y==ty);}static int get(int v,int lim){int lo=cl,hi=ch,g=lo+hi-v;if(ou){if(v==0)g/=2;else if(v==lim)g=(lim+g)/2;}ou=false;if(g==v)g=v+1;if(g<0){g=0;ou=true;}else if(g>lim){g=lim;ou=true;}int m=(g+v)/2,ml=(g+v-1)/2,mh=(g+v+1)/2;if(g>v){wl=mh;wh=hi;dl=lo;dh=ml;}else{wl=lo;wh=ml;dl=mh;dh=hi;}return g;}}
